import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"贯世之影","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/贯世之影.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/贯世之影.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/6.可升级/贯世之影.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"贯世之影",tabindex:"-1"},[p("贯世之影 "),r("a",{class:"header-anchor",href:"#贯世之影","aria-label":'Permalink to "贯世之影"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),n('<h1 id="贯世之影-1" tabindex="-1">贯世之影 <a class="header-anchor" href="#贯世之影-1" aria-label="Permalink to &quot;贯世之影&quot;">​</a></h1><p>贯世之影<br> 魔幻本质<br> 物品-载具</p><p>传说中魔王手下的四天王之一的坐骑，或者说就是本体的存在！<br> 贯世之影是一辆黑色高级摩托车，仅能单人乘坐，使用【贯世之莹】作为主要攻击手段。<br> 贯世之影与下属武器都为差价升级，为模板标准价格。</p><p>D级：贯世之影-奔驰于尘土之上<br> 载具类型：轻型载具<br> 体积：5<br> 结构值：22<br> 装甲：6<br> 速度：基础140米/轮<br> 机动性：普通<br> 载员情况：驾驶员1，体积不超过5<br> 【尖端空间魔法】：贯世之影的0.8*0.7*0.65米的金属后备箱实际上使用了最新的空间伸展魔法，实际上是一个10立方米的储存空间，取出/放入物品需要一个迅捷动作，无法存储独立单位。<br> 【贯世之莹】：贯世之莹是贯世之影的载具武装，安装在车舵前，是一把特殊的霰弹枪，在购买下属武装前不具有霰弹枪的模板效果，仅具有射程40米，造成穿刺伤害的能力。使用贯世之莹攻击需要使用载具攻击检定，但同时仍适用于驾驶者使用霰弹枪的能力效果。</p><p>C级：贯世之影-奔驰于尘土之上-飞溅于浩海之中<br> 载具类型：轻型载具<br> 体积：5<br> 结构值：36<br> 装甲：10<br> 速度：基础180米/轮<br> 机动性：良好<br> 载员情况：驾驶员1，体积不超过5<br> 【尖端空间魔法】：贯世之影的0.8*0.7*0.65米的金属后备箱实际上使用了最新的空间伸展魔法，实际上是一个10立方米的储存空间，取出/放入物品需要一个迅捷动作，无法存储独立单位。<br> 【贯世之莹】：贯世之莹是贯世之影的载具武装，安装在车舵前，是一把特殊的霰弹枪，在购买下属武装前不具有霰弹枪的模板效果，仅具有射程40米，造成穿刺伤害的能力。使用贯世之莹攻击需要使用载具攻击检定，但同时仍适用于驾驶者使用霰弹枪的能力效果。<br> 【奔行世间】：贯世之影可以在疾驰移动时可以使用【贯世之莹】进行射击。</p><p>B级：贯世之影-奔驰于尘土之上-飞溅于浩海之中-突破于苍穹之下<br> 载具类型：轻型载具<br> 体积：5<br> 结构值：52<br> 装甲：14<br> 速度：基础280米/轮<br> 机动性：完美<br> 飞行机动性：普通<br> 载员情况：驾驶员1，体积不超过5<br> 【尖端空间魔法】：贯世之影的0.8*0.7*0.65米的金属后备箱实际上使用了最新的空间伸展魔法，实际上是一个10立方米的储存空间，取出/放入物品需要一个迅捷动作，无法存储独立单位。<br> 【贯世之莹】：贯世之莹是贯世之影的载具武装，安装在车舵前，是一把特殊的霰弹枪，在购买下属武装前不具有霰弹枪的模板效果，仅具有射程40米，造成穿刺伤害的能力。使用贯世之莹攻击需要使用载具攻击检定，但同时仍适用于驾驶者使用霰弹枪的能力效果。<br> 【奔行世间】：贯世之影可以在疾驰移动时可以使用【贯世之莹】进行射击，贯世之影现在能展开踏空术式，具有飞行能力，机动性为普通。<br> 【超时空骑兵】：现在骑乘贯世之影，在回合外反射动作使用紧急规避受到首次攻击时，你视为已经离开攻击范围，正常遵循招架流程。</p><p>贯世之影下属武装-贯世之莹<br> 魔幻本质<br> 物品-载具-下属武装</p><p>贯世之莹是一把装在贯世之影车舵前的特殊武装，使用霰弹枪模板进行攻击，适用驾驶员使用霰弹枪的能力效果<br> 贯世之莹是差价升级。</p><p>D级：贯世之莹-萤虫辉光<br> 分类：霰弹枪<br> 武器伤害：7L<br> 武器特性：高速5 攻击距离不超过15米内的单位时获得2威猛<br> 速射等级：长点射<br> 基础射程：40米<br> 伤害类型：物理-穿刺<br> 效果：射出带有法术精光的子弹，具有【法破】效果，被命中的单位会额外受到1点固定的光能伤害。</p><p>C级：贯世之莹-萤虫辉光-举火炎光<br> 分类：霰弹枪<br> 武器伤害：12L<br> 武器特性：高速5 攻击距离不超过15米内的单位时获得2威猛<br> 速射等级：长点射<br> 基础射程：40米<br> 伤害类型：物理-穿刺<br> 效果：射出带有法术精光的子弹，具有【法破】效果，被命中的单位会额外受到1点固定的光能伤害，同时选择命中的一个目标释放辉光术式，其在你眼中将被淡淡的辉光包裹，你视为对其具有【真实视觉】，持续1小时，选择更换目标会提前终止这个效果。</p><p>B级：贯世之莹-萤虫辉光-举火炎光-皓月灵光<br> 分类：霰弹枪<br> 武器伤害：19L<br> 武器特性：高速5 攻击距离不超过15米内的单位时获得2威猛<br> 速射等级：长点射<br> 基础射程：40米<br> 伤害类型：能量-光能<br> 效果：射出带有法术精光的子弹，具有【法破】效果，被命中的单位会额外受到1点固定的光能伤害，同时选择命中的一个目标释放辉光术式，其在你眼中将被淡淡的辉光包裹，你视为对其具有【真实视觉】，持续1小时，选择更换目标会提前终止这个效果。<br> 贯世之莹现在具有【能量武器】特性，用其进行的攻击检定加骰提升一级，至多8加骰，每回合一次，用该武装攻击时可以选择通过月灵的力量重掷一次，结果取高。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
